Load data for decades


Code
library(rlang)
library(cbbplotR)
options(chromote.headless = "new")

# ------- Decades data

# ---------- UNC data 
unc &lt;- readr::read_csv("unc_data.csv")

# manually add in other numbers from sports-refernece and wikipedia 

unc_acct &lt;- c(1981, 1982, 1989, 1991, 1994, 1997, 1998, 2007, 2008, 2016)

unc_rs &lt;- c(1982, 1983, 1984, 1985, 1987, 1988, 1993, 1995, 2001, 2005, 
        2007, 2008, 2009, 2011, 2012, 2016, 2017, 2019, 2024)

unc_f4 &lt;- c(1981, 1982, 1991, 1993, 1995, 1997, 1998, 2000, 2005, 2008, 2009, 2016, 2017, 2022)

unc_titles &lt;- c(1982, 1993, 2005, 2009, 2017)

# function to count by decade 
convert_to_decade &lt;- function(years) {
  paste0(floor(years / 10) * 10, "s")
}

unc_decade_counts &lt;- data.frame(
  Decade = unique(c(convert_to_decade(unc_acct), convert_to_decade(unc_rs), convert_to_decade(unc_f4), convert_to_decade(unc_titles)))
) |&gt;
  dplyr::mutate(
    ACCT = sapply(Decade, function(d) sum(convert_to_decade(unc_acct) == d)),
    RS = sapply(Decade, function(d) sum(convert_to_decade(unc_rs) == d)),
    F4 = sapply(Decade, function(d) sum(convert_to_decade(unc_f4) == d)),
    Titles = sapply(Decade, function(d) sum(convert_to_decade(unc_titles) == d)),
  ) |&gt;
  dplyr::arrange(Decade)

# summarize the data
unc_summary &lt;- unc |&gt;
  dplyr::filter(Year &gt; 1979) |&gt; 
  dplyr::mutate(
    Decade = paste0(floor(Year / 10) * 10, "s")  # Convert Year to decade format
  ) |&gt;
  dplyr::group_by(Decade) |&gt;
  dplyr::summarize(
    Total_Wins = sum(W...6, na.rm = TRUE),
    Total_Losses = sum(L, na.rm = TRUE),
    Win_Percentage = Total_Wins / (Total_Wins + Total_Losses)
  ) |&gt;
  dplyr::arrange(Decade)

# summarize the win percentages in a list 
unc_with_decade &lt;- unc |&gt;
  dplyr::filter(Year &gt; 1979) |&gt; 
  dplyr::mutate(
    Decade = paste0(floor(Year / 10) * 10, "s")  # Convert Year to decade format
  ) |&gt;
  dplyr::group_by(Decade) |&gt;
  dplyr::summarize(
    Yearly_Win_Pcts = list(rev(winpct))  # Store win percentages as a list per decade
  ) |&gt;
  dplyr::arrange(Decade)

# all the tables 
unc_hist &lt;- unc_summary |&gt; 
  dplyr::left_join(unc_decade_counts, by = "Decade") |&gt; 
  dplyr::left_join(unc_with_decade, by = "Decade") |&gt; 
  dplyr::mutate(team = "North Carolina",
                team_two = "North Carolina")

# State --------------------
state &lt;- readr::read_csv("state.csv")

st_acct &lt;- c(1983, 1987, 2024)

st_rs &lt;- c(1985, 1989)

st_f4 &lt;- c(1983, 2024)

st_titles &lt;- c(1983)

st_decade_counts &lt;- data.frame(
  Decade = unique(c(convert_to_decade(st_acct), convert_to_decade(st_rs), convert_to_decade(st_f4), convert_to_decade(st_titles)))
) |&gt;
  dplyr::mutate(
    ACCT = sapply(Decade, function(d) sum(convert_to_decade(st_acct) == d)),
    RS = sapply(Decade, function(d) sum(convert_to_decade(st_rs) == d)),
    F4 = sapply(Decade, function(d) sum(convert_to_decade(st_f4) == d)),
    Titles = sapply(Decade, function(d) sum(convert_to_decade(st_titles) == d)),
  ) |&gt;
  dplyr::arrange(Decade)

# summarize the data
state_summary &lt;- state |&gt;
  dplyr::mutate(
    Wins = as.numeric(wins),
    Losses = as.numeric(losses)
  ) |&gt; 
  dplyr::mutate(
    Decade = paste0(floor(Year / 10) * 10, "s")  # Convert Year to decade format
  ) |&gt;
  dplyr::group_by(Decade) |&gt;
  dplyr::summarize(
    Total_Wins = sum(Wins),
    Total_Losses = sum(Losses),
    Win_Percentage = Total_Wins / (Total_Wins + Total_Losses)
  ) |&gt;
  dplyr::arrange(Decade)

# summarize the win percentages in a list 
state_with_decade &lt;- state |&gt;
  dplyr::mutate(
    Decade = paste0(floor(Year / 10) * 10, "s")  # Convert Year to decade format
  ) |&gt;
  dplyr::group_by(Decade) |&gt;
  dplyr::summarize(
    Yearly_Win_Pcts = list(rev(winpct))  # Store win percentages as a list per decade
  ) |&gt;
  dplyr::arrange(Decade)

# all the tables 
state_hist &lt;- state_summary |&gt; 
  dplyr::left_join(st_decade_counts, by = "Decade") |&gt; 
  dplyr::left_join(state_with_decade, by = "Decade") |&gt; 
  dplyr::mutate(team = "North Carolina St.",
                team_two = "North Carolina St.")

# Duke 
duke &lt;- readr::read_csv("duke.csv")

duke_acct &lt;- c(1980, 1986, 1988, 1992, 1999, 2000, 2001, 2002, 2003, 2005, 2006, 
          2009, 2010, 2011, 2017, 2019, 2023, 2025)

duke_rs &lt;- c(1986, 1991, 1992, 1994, 1997, 1998, 1999, 2000, 2001, 2004, 2006, 
        2010, 2022, 2025)

duke_f4 &lt;- c(1986, 1988, 1989, 1990, 1991, 1992, 1994, 1999, 2001, 2004,
        2010, 2015, 2022, 2025)

duke_titles &lt;- c(1991, 1992, 2001, 2010, 2015)

convert_to_decade &lt;- function(years) {
  paste0(floor(years / 10) * 10, "s")
}

duke_decade_counts &lt;- data.frame(
  Decade = unique(c(convert_to_decade(duke_acct), convert_to_decade(duke_rs), convert_to_decade(duke_f4), convert_to_decade(duke_titles)))
) |&gt;
  dplyr::mutate(
    ACCT = sapply(Decade, function(d) sum(convert_to_decade(duke_acct) == d)),
    RS = sapply(Decade, function(d) sum(convert_to_decade(duke_rs) == d)),
    F4 = sapply(Decade, function(d) sum(convert_to_decade(duke_f4) == d)),
    Titles = sapply(Decade, function(d) sum(convert_to_decade(duke_titles) == d)),
  ) |&gt;
  dplyr::arrange(Decade)

# summarize the data
duke_summary &lt;- duke |&gt;
  dplyr::mutate(
    Wins = as.numeric(wins),
    Losses = as.numeric(losses)
  ) |&gt; 
  dplyr::mutate(
    Decade = paste0(floor(Year / 10) * 10, "s")  # Convert Year to decade format
  ) |&gt;
  dplyr::group_by(Decade) |&gt;
  dplyr::summarize(
    Total_Wins = sum(Wins),
    Total_Losses = sum(Losses),
    Win_Percentage = Total_Wins / (Total_Wins + Total_Losses)
  ) |&gt;
  dplyr::arrange(Decade)

# summarize the win percentages in a list 
duke_with_decade &lt;- duke |&gt;
  dplyr::mutate(
    Decade = paste0(floor(Year / 10) * 10, "s")  # Convert Year to decade format
  ) |&gt;
  dplyr::group_by(Decade) |&gt;
  dplyr::summarize(
    Yearly_Win_Pcts = list(rev(winpct))  # Store win percentages as a list per decade
  ) |&gt;
  dplyr::arrange(Decade)

# all the tables 
duke_hist &lt;- duke_summary |&gt; 
  dplyr::left_join(duke_decade_counts, by = "Decade") |&gt; 
  dplyr::left_join(duke_with_decade, by = "Decade") |&gt; 
  dplyr::mutate(team = "Duke", team_two = "Duke")

# --------------------------------------------- 

all_hist &lt;- unc_hist |&gt; 
  dplyr::bind_rows(state_hist, duke_hist) |&gt; 
  dplyr::relocate(team)




Triangle decades table


Code
tri_header &lt;- glue::glue(
  "&lt;div style='display: flex; justify-content: space-between; align-items: center;'&gt;
      &lt;div&gt;
       &lt;img src='https://a.espncdn.com/combiner/i?img=/redesign/assets/img/icons/ESPN-icon-basketball.png'
       style='height: 45px; width: auto; vertical-align: middle;'&gt;
     &lt;/div&gt;
     &lt;div style='flex-grow:1; margin-left: 30px; margin-right: 30px'&gt;
       &lt;span style='display: block; font-weight: bold; text-align: center; font-size: 24px;'&gt;Triangle hoops over the past five decades&lt;/span&gt;
       &lt;span style='font-size: 12.5px; font-weight: normal; display: block; text-align: center;'&gt;Performance across the ACC, NCAA Tournament, and overall win percentage.&lt;/span&gt;
     &lt;/div&gt;
     &lt;div&gt;
       &lt;img src='https://a.espncdn.com/combiner/i?img=/redesign/assets/img/icons/ESPN-icon-basketball.png' 
       style='height: 45px; width: auto; vertical-align: middle;'&gt;
     &lt;/div&gt;
   &lt;/div&gt;
  &lt;br&gt;"
)


decade_tbl &lt;- all_hist |&gt; 
  dplyr::mutate(
    dplyr::across(
      where(is.numeric),
      ~ tidyr::replace_na(.x, 0)
    )
  ) |&gt; 
  dplyr::arrange(Decade, -Titles, -Win_Percentage) |&gt; 
  dplyr::mutate(record = paste0(Total_Wins, "-", Total_Losses)) |&gt; 
  dplyr::relocate(Win_Percentage, .after = Titles) |&gt;
  dplyr::mutate(
    Titles = dplyr::case_when(
      Titles %% 1 == 0 ~ strrep("trophy,", Titles),
      Titles %% 1 != 0 ~ paste0(strrep("trophy,", floor(Titles)), "trophy"))
  ) |&gt; 
  cbbplotR::gt_cbb_teams(team, team, include_name = FALSE) |&gt; 
  cbbplotR::gt_cbb_teams(team_two, team_two, include_name = FALSE) |&gt; 
  dplyr::group_by(Decade) |&gt; 
  gt::gt() |&gt; 
  gt::fmt_markdown(team) |&gt; 
  gt::fmt_markdown(team_two) |&gt; 
  gtUtils::gt_theme_gtutils() |&gt; 
  gt::fmt_icon(
    columns = c(Titles),
    rows = c(1, 2, 4, 5, 7, 8, 10, 11),
    fill_color = "orange"
  ) |&gt; 
  gt::cols_hide(columns = c(Total_Wins, Total_Losses)) |&gt; 
  gt::fmt_number(Win_Percentage, decimals = 3) |&gt; 
  gtExtras::gt_merge_stack(
    col1 = Win_Percentage,
    col2 = record,
    palette = c("black", "#333333")
  ) |&gt; 
  gtUtils::gt_column_subheaders(
    Win_Percentage = list(heading = "Win %", subtitle = "W-L"),
    ACCT = list(heading = "Titles", subtitle = "Tournament"),
    RS = list(heading = "Regular", subtitle = "Season"),
    F4 = list(heading = "Final Fours", subtitle = "# of times"),
    Titles = list(heading = "Titles", subtitle = "# of titles"),
    heading_color = "black",
    subtitle_color = "gray"
  ) |&gt; 
  gt::cols_label(team = "", team_two = "") |&gt; 
  gt::tab_spanner(
    columns = c(ACCT, RS),
    label = "ACC Championships"
  ) |&gt; 
  gt::tab_spanner(
    columns = c(F4, Titles),
    label = "NCAA Tournament"
  ) |&gt; 
  gt::cols_label(
    Decade = ""
  ) |&gt; 
  gt::cols_nanoplot(
    columns = Yearly_Win_Pcts,
    reference_line = .70,
    autohide = TRUE,
    plot_type = "line",
    new_col_label = "Over time",
    before = "team_two",
    options = gt::nanoplot_options(
      data_area_fill_color = "#C5C5FF",
      reference_line_color = "#333333",
      show_data_area = TRUE,
      show_data_points = FALSE
    )
  ) |&gt; 
  gt::tab_header(title = gt::html(tri_header)) |&gt;
  gt::tab_source_note(source_note = gt::html("&lt;hr&gt;Over time column shows win percentage by season throughout the decade (dashed line indicates a .700 win percentage)&lt;br&gt;Data grouped by each decade, and sorted by National titles first, and win percentage second &lt;br&gt;Decades include the season's final year (i.e. 2009-10 is part of the 2010s)&lt;hr&gt;&lt;br&gt;&lt;b&gt;Table by Chris at Bless your Chart | data via sports-reference.com | April 9, 2025&lt;/b&gt;")) |&gt; 
  gt::data_color(
    columns = c(ACCT, RS, F4, Win_Percentage),
    direction = c("column"),
    method = c("numeric"),
    palette = c("#d7191c", "#fdae61", 
                "#ffffbf", "#a6d96a", 
                "#1a9641"),
    alpha = 0.6
  ) |&gt;
  gt::cols_align(team, align = "right") |&gt; 
  gt::tab_style(
    locations = gt::cells_column_labels(),
    style = gt::cell_text(
      font = gt::google_font("Signika Negative"),
      weight = "650",
      size = gt::px(14)
    )
  ) |&gt; 
  gt::tab_style(
    locations = gt::cells_body(columns = Decade),
    style = gt::cell_text(
      font = gt::google_font("Signika Negative"),
      weight = "bold"
    )
  ) |&gt; 
  gt::tab_style(
    locations = gt::cells_column_spanners(),
    style = gt::cell_text(
      font = gt::google_font("Signika Negative"),
      weight = 850,
      size = gt::px(14)
    )
  ) |&gt;
  gt::tab_style(
    locations = gt::cells_source_notes(),
    style = gt::cell_text(
      font = gt::google_font("Signika Negative"),
      size = gt::px(11.5),
      weight = 250
    )
  ) |&gt;
  gt::tab_style(
    locations = gt::cells_row_groups(),
    style = list(
      gt::cell_text(
        font = gt::google_font("Signika Negative"),
        weight = 850,
        size = gt::px(16),
        color = "black",
        align = "left"
      ),
      gt::cell_fill(
        color = "#C5C5FF"
      )
    )
  ) |&gt; 
  gt::tab_style(
    style = list(
      gt::cell_text(font = gt::google_font("Signika Negative")
      )
    ),
    locations = gt::cells_body(
      columns = c(team)
    )
  ) |&gt; 
  gtUtils::gt_border_grid(color = "black",
                          weight = 1.5,
                          include_labels = FALSE) |&gt; 
  gtUtils::gt_border_bars_bottom(c("#012169", "#56a0d3", "#CC0000")) |&gt; 
  gt::tab_options(table.width = gt::px(600))


gtUtils::gt_save_crop(
  decade_tbl,
  file = "tri_decade_tbl.png",
  whitespace = 60,
  bg = "#FFFDF5"
)

