library(cbbplotR)
library(rlang)

dc_data &lt;- readr::read_csv("np-dc-data.csv") |&gt; 
  dplyr::select(team = school, top_ten)

# list out the teams
dc_teams &lt;- dc_data |&gt; 
  dplyr::pull(team)

# comment out cfbfastR function 
# get_cfb_records &lt;- function(years = 1993:2024) {
#  purrr::map_dfr(years, cfbfastR::cfbd_game_records)
# }

# all_records &lt;- get_cfb_records()

fb_records &lt;- readr::read_csv("fb_records.csv")

fb_data &lt;- fb_records |&gt; 
  dplyr::filter(team %in% dc_teams) |&gt; 
  dplyr::mutate(
    fb_win_pct = (total_wins + 0.5 * total_ties) / (total_wins + total_losses + total_ties)
  ) |&gt; 
  dplyr::group_by(team) |&gt; 
  dplyr::summarise(
    all_fb_win_pct = list(fb_win_pct),
    overall_fb_win_pct = sum(total_wins + 0.5 * total_ties, na.rm = TRUE) / 
                      sum(total_wins + total_losses + total_ties, na.rm = TRUE),
  )

bball_wins &lt;- readr::read_csv("bball-wins.csv") |&gt; 
  dplyr::rename(team = Team, bball_win_pct = `W/L%`) |&gt; 
  dplyr::mutate(team = dplyr::if_else(team == "Louisiana State", "LSU", team)) |&gt; 
  dplyr::filter(team %in% dc_teams)

# combine data 
all_sports &lt;- dc_data |&gt; 
      dplyr::left_join(bball_wins, by = "team") |&gt; 
  dplyr::left_join(fb_data, by = "team") |&gt; 
  dplyr::select(team, top_ten, bball_win_pct, overall_fb_win_pct, all_fb_win_pct) |&gt; 
  dplyr::arrange(-top_ten)




