# -------------- Sankey fun 
generate_sankey &lt;- function(team_name) {
  edges_raw &lt;- portal |&gt;
    dplyr::filter(
      season == 2025,
      origin == team_name | destination == team_name
    ) |&gt;
    dplyr::select(from = origin, to = destination) |&gt;
    dplyr::filter(!is.na(from), !is.na(to))

  # count the number of transfers
  edge_counts &lt;- edges_raw |&gt;
    dplyr::count(from, to, name = "value")

  # count by team
  transfer_counts &lt;- edge_counts |&gt;
    tidyr::pivot_longer(cols = c(from, to), values_to = "team") |&gt;
    dplyr::count(team, wt = value, name = "transfer_count")

  nodes &lt;- tibble::tibble(name = unique(c(edge_counts$from, edge_counts$to))) |&gt;
    dplyr::left_join(transfer_counts, by = c("name" = "team")) |&gt;
    dplyr::mutate(
      label = dplyr::if_else(
        name == team_name,
        paste0(team_name, " ", transfer_count),
        dplyr::if_else(transfer_count &gt; 1, paste0(transfer_count, " ", name), name)
      ),
      transfer_count = dplyr::coalesce(transfer_count, 0)
    ) |&gt;
    dplyr::arrange(desc(name == team_name), desc(transfer_count))

  # adjust order
  edges_indexed &lt;- edge_counts |&gt;
    dplyr::mutate(
      source = match(from, nodes$name) - 1,
      target = match(to, nodes$name) - 1
    )

  # add Sankey diagram
  sankey &lt;- networkD3::sankeyNetwork(
    Links = edges_indexed,
    Nodes = nodes,
    Source = "source",
    Target = "target",
    Value = "value",
    NodeID = "label",
    fontSize = 13,
    nodeWidth = 30,
    sinksRight = FALSE
  )

  sankey$x$links$color &lt;- "rgba(160,160,160,0.4)"  # light gray
  sankey$x$nodes$color &lt;- ifelse(nodes$name == team_name, "blue", "steelblue")

  return(sankey)
}




