                                           home_team),
                away_team = dplyr::if_else(away_team == "Miami (FL) ", "Miami (FL)", 
                                           away_team) 
  ) 


# find standings and run diffs 
home_diffs &lt;- acc_results_2025 |&gt;
  dplyr::mutate(h_diff = home_team_score - away_team_score) |&gt;
  dplyr::group_by(home_team) |&gt;
