  dplyr::count() |&gt;
  tidyr::pivot_wider( 
    names_from = h_result,
    values_from = n)|&gt;
  dplyr::rename(team = home_team, h_w = W, h_l = L)

away_results &lt;- acc_results_2025 |&gt;
