    cum_win = cumsum(win),
    cum_loss = cumsum(loss),
    win_diff = cum_win - cum_loss,
    cum_games = cum_win + cum_loss,
    cum_win_pct = cum_win / cum_games
  ) |&gt; 
  dplyr::ungroup()

target_date &lt;- as.Date("2025-05-14")

team_labels &lt;- acc_plot_data |&gt; 
  dplyr::arrange(desc(date), -contest_id) |&gt; 
  dplyr::group_by(team) |&gt; 
  dplyr::slice_max(order_by = date, n = 1) |&gt; 
  dplyr::left_join(standings, by = c("team")) |&gt; 
  dplyr::ungroup() |&gt; 
  dplyr::group_by(cum_win_pct) |&gt;
  dplyr::mutate(
    stagger = dplyr::row_number() - (dplyr::n() + 1) / 2,
    y_staggered = win_diff + stagger * 0.45
  ) |&gt; 
  dplyr::ungroup() |&gt; 
  dplyr::mutate(
    y_staggered = dplyr::case_when(
      team == "NC State" ~ y_staggered + 0.3,
      team == "Georgia Tech" ~ y_staggered - 0.3,
      TRUE ~ y_staggered
    )
  ) |&gt; 
  dplyr::distinct(team, .keep_all = TRUE)


extension_date &lt;- as.Date("2025-05-11")

extend_rows &lt;- acc_plot_data |&gt; 
  dplyr::group_by(team) |&gt; 
  dplyr::filter(date == max(date)) |&gt; 
  dplyr::mutate(date = extension_date) |&gt; 
  dplyr::ungroup()

acc_plot_data_extend &lt;- dplyr::bind_rows(acc_plot_data, extend_rows)

ggplot2::ggplot(acc_plot_data_extend, ggplot2::aes(x = date, y = win_diff, color = team)) +
  ggplot2::geom_smooth(linewidth = 0.5, se = FALSE) +
  ggplot2::geom_text(
