coaching_data &lt;- readr::read_csv("coaching-data.csv")

waffle_data_top20 &lt;- coaching_data |&gt;
  dplyr::mutate(
    total_pay_num = readr::parse_number(total_pay),
    buyout_num = readr::parse_number(buyout)
  ) |&gt;
  dplyr::filter(!is.na(total_pay_num), !is.na(buyout_num)) |&gt;
  dplyr::arrange(dplyr::desc(total_pay_num)) |&gt;
  dplyr::slice_head(n = 20) |&gt;
  dplyr::arrange(dplyr::desc(buyout_num)) |&gt;
  dplyr::mutate(
    salary_squares = round(total_pay_num / 1e6),
    buyout_squares = round(buyout_num / 1e6),
    # adjust james franklin
    coach_label = dplyr::case_when(
      coach == "James Franklin" ~ "James Franklin (Fired)&lt;br&gt;Penn State",
      TRUE ~ stringr::str_c(coach, "&lt;br&gt;", team)
    )
  )

# order by buyout
coach_order_levels &lt;- unique(waffle_data_top20$coach_label)

# pivot data
waffle_data_top20 &lt;- waffle_data_top20 |&gt;
  dplyr::select(coach_label, salary_squares, buyout_squares) |&gt;
  tidyr::pivot_longer(
    cols = c(salary_squares, buyout_squares),
    names_to = "metric",
    values_to = "n"
  ) |&gt;
  dplyr::mutate(
    metric = dplyr::case_when(
      metric == "salary_squares" ~ "Annual Salary",
      metric == "buyout_squares" ~ "Contract Buyout"
    ),
    coach_label = factor(coach_label, levels = coach_order_levels)
  )

waffle_plot_top20 &lt;- waffle_data_top20 |&gt;
  ggplot2::ggplot(ggplot2::aes(fill = metric, values = n)) +
  waffle::geom_waffle(
    color = "white", 
    size = 0.3, 
    n_rows = 10,
    flip = TRUE,
    radius = grid::unit(3, "pt"),
    height = 0.9,
    width = 0.9
  ) +
  ggplot2::facet_wrap(~coach_label, ncol = 4, strip.position = "top") +
  ggplot2::scale_x_discrete(expand = c(0, 0)) +
  ggplot2::scale_y_continuous(
    labels = function(x) x * 10,
